		if (sunk == 0) {
			return 0;
		}
		SlotPlan[] result = new SlotPlan[n];
		int at = 0;
		for (int i = 0; i < n; i++) {
			if (!candidate[i]) {
				result[at++] = ordered[i];
			}
		}
		for (int i = 0; i < n; i++) {
			if (candidate[i]) {
				result[at++] = ordered[i];
			}
		}
